dataSet.query:
ВЫБРАТЬ энргЗадачаПИД.Дата КАК Дата, энргЗадачаПИД.Абонент КАК Абонент, энргЗадачаПИД.Исполнитель КАК Ответственный, энргЗадачаПИД.Ссылка КАК Задача, энргЗадачаПИД.ДатаВыполнения КАК ДатаВыполнения, энргЗадачаПИД.Выполнена КАК Выполнена ПОМЕСТИТЬ ВТ_ТекущиеОтветственные ИЗ Задача.энргЗадачаПИД КАК энргЗадачаПИД ГДЕ НЕ энргЗадачаПИД.ПометкаУдаления ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ энргЗадачаПИДИсторияПеренаправленийЗадачи.НомерСтроки КАК НомерСтроки, энргЗадачаПИДИсторияПеренаправленийЗадачи.НовыйИсполнитель КАК НовыйИсполнитель, энргЗадачаПИДИсторияПеренаправленийЗадачи.Перенаправил КАК Перенаправил, энргЗадачаПИДИсторияПеренаправленийЗадачи.ДатаПеренаправления КАК ДатаПеренаправления, ВТ_ТекущиеОтветственные.Задача КАК Задача, ВТ_ТекущиеОтветственные.Дата КАК Дата, ВТ_ТекущиеОтветственные.Абонент КАК Абонент, ВТ_ТекущиеОтветственные.ДатаВыполнения КАК ДатаВыполнения ПОМЕСТИТЬ ВТ_Перенаправления ИЗ ВТ_ТекущиеОтветственные КАК ВТ_ТекущиеОтветственные ВНУТРЕННЕЕ СОЕДИНЕНИЕ Задача.энргЗадачаПИД.ИсторияПеренаправленийЗадачи КАК энргЗадачаПИДИсторияПеренаправленийЗадачи ПО ВТ_ТекущиеОтветственные.Задача = энргЗадачаПИДИсторияПеренаправленийЗадачи.Ссылка ГДЕ энргЗадачаПИДИсторияПеренаправленийЗадачи.ДатаПеренаправления <> ДАТАВРЕМЯ(1, 1, 1, 0, 0, 0) ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ МАКСИМУМ(ВТ_Перенаправления.НомерСтроки) КАК НомерСтроки, ВТ_Перенаправления.Задача КАК Задача ПОМЕСТИТЬ ВТ_СтрокаПоследПеренаправления ИЗ ВТ_Перенаправления КАК ВТ_Перенаправления
СГРУППИРОВАТЬ ПО ВТ_Перенаправления.Задача ;
//////////////////////////////////////////////////////////////////////////////// ВЫБРАТЬ ВТ_Перенаправления.Перенаправил КАК Перенаправил, ВТ_Перенаправления.ДатаПеренаправления КАК ДатаОкончанияРаботыСЗаявкой, ВТ_Перенаправления1.НовыйИсполнитель КАК НовыйИсполнитель, ВТ_Перенаправления.Задача КАК Задача, ВТ_Перенаправления.Абонент КАК Абонент, ВЫБОР КОГДА НЕ ВТ_Перенаправления1.ДатаПеренаправления ЕСТЬ NULL ТОГДА РАЗНОСТЬДАТ(ВТ_Перенаправления1.ДатаПеренаправления, ВТ_Перенаправления.ДатаПеренаправления, ДЕНЬ) КОГДА ВТ_Перенаправления.Дата <> ДАТАВРЕМЯ(1, 1, 1, 0, 0, 0) ТОГДА РАЗНОСТЬДАТ(ВТ_Перенаправления.Дата, ВТ_Перенаправления.ДатаПеренаправления, ДЕНЬ) ИНАЧЕ NULL КОНЕЦ КАК ПродолжительностьРаботыСЗаявкой, ВЫБОР КОГДА НЕ ВТ_Перенаправления1.ДатаПеренаправления ЕСТЬ NULL ТОГДА ВТ_Перенаправления1.ДатаПеренаправления КОГДА ВТ_Перенаправления.Дата <> ДАТАВРЕМЯ(1, 1, 1, 0, 0, 0) ТОГДА ВТ_Перенаправления.Дата ИНАЧЕ NULL КОНЕЦ КАК ДатаНачалаРаботыСЗаявкой ИЗ ВТ_Перенаправления КАК ВТ_Перенаправления ЛЕВОЕ СОЕДИНЕНИЕ ВТ_Перенаправления КАК ВТ_Перенаправления1 ПО ВТ_Перенаправления.Задача = ВТ_Перенаправления1.Задача И (ВТ_Перенаправления.НомерСтроки = ВТ_Перенаправления1.НомерСтроки + 1)
ОБЪЕДИНИТЬ ВСЕ
ВЫБРАТЬ ВТ_Перенаправления.Перенаправил, ВЫБОР КОГДА ВТ_ТекущиеОтветственные.Выполнена И ВТ_ТекущиеОтветственные.ДатаВыполнения <> ДАТАВРЕМЯ(1, 1, 1, 0, 0, 0) ТОГДА ВТ_ТекущиеОтветственные.ДатаВыполнения ИНАЧЕ NULL КОНЕЦ, ВТ_ТекущиеОтветственные.Ответственный, ВТ_ТекущиеОтветственные.Задача, ВТ_ТекущиеОтветственные.Абонент, ВЫБОР КОГДА ВТ_ТекущиеОтветственные.Выполнена И ВТ_ТекущиеОтветственные.ДатаВыполнения <> ДАТАВРЕМЯ(1, 1, 1, 0, 0, 0) ТОГДА РАЗНОСТЬДАТ(ЕСТЬNULL(ВТ_Перенаправления.ДатаПеренаправления, ВТ_ТекущиеОтветственные.Дата), ВТ_ТекущиеОтветственные.ДатаВыполнения, ДЕНЬ) ИНАЧЕ NULL КОНЕЦ, ЕСТЬNULL(ВТ_Перенаправления.ДатаПеренаправления, ВТ_ТекущиеОтветственные.Дата) ИЗ ВТ_ТекущиеОтветственные КАК ВТ_ТекущиеОтветственные ЛЕВОЕ СОЕДИНЕНИЕ ВТ_СтрокаПоследПеренаправления КАК ВТ_СтрокаПоследПеренаправления ПО ВТ_ТекущиеОтветственные.Задача = ВТ_СтрокаПоследПеренаправления.Задача ЛЕВОЕ СОЕДИНЕНИЕ ВТ_Перенаправления КАК ВТ_Перенаправления ПО ВТ_ТекущиеОтветственные.Задача = ВТ_Перенаправления.Задача И (ВТ_СтрокаПоследПеренаправления.НомерСтроки = ВТ_Перенаправления.НомерСтроки)
